module TopModule (
    input [39:0] vector_a,
    input [39:0] vector_b,
    output reg [15:0] dot_product_out
);
    integer i;
    always @(*) begin
        dot_product_out = 16'b0;
        for (i = 0; i < 5; i = i + 1) begin
            dot_product_out = dot_product_out + (vector_a[i*8 +: 8] * vector_b[i*8 +: 8]);
        end
    end
endmodule

